use grep_matcher::Match;

#[test]
fn test_match_positions() {
    let m = Match::new(5, 10);
    assert_eq!(m.start(), 5);
    assert_eq!(m.end(), 10);
}

#[test]
fn test_match_len() {
    let m = Match::new(0, 7);
    assert_eq!(m.len(), 7);
}

#[test]
fn test_match_is_empty() {
    let empty = Match::new(5, 5);
    assert!(empty.is_empty());

    let non_empty = Match::new(0, 3);
    assert!(!non_empty.is_empty());
}
